<?php require_once __DIR__.'/tg_auth.php'; tg_session_start();$th=$_COOKIE['theme']??'light';$th=$th==='dark'?'dark':'light';$thCls=$th==='dark'?'dark-theme':'';tg_handle_bootstrap();if(!isset($_SESSION['tg_id'])){?><!DOCTYPE html><html lang="en" class="<?= $thCls ?>"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Loading…</title><link rel="stylesheet" href="style.css"><script src="https://telegram.org/js/telegram-web-app.js"></script><script src="script.js"></script></head><body><div id="tg-bootstrap"></div></body></html><?php exit;}header('Content-Type: text/html; charset=UTF-8');require_once __DIR__.'/config.php';require_once __DIR__.'/db.php';require_once __DIR__.'/oe_weeks.php';require_once __DIR__.'/helpers.php';function initials(string $s):string{$stop=['of','and','the','de','la','si','și','în','din','ale','a','cu','pe','şi'];$p=preg_split('/[\s\-]+/u',trim($s),-1,PREG_SPLIT_NO_EMPTY);$o='';foreach($p as $w){$lw=mb_strtolower($w,'UTF-8');if(in_array($lw,$stop,true))continue;$o.=mb_strtoupper(mb_substr($w,0,1,'UTF-8'),'UTF-8');}return $o?:mb_strtoupper(mb_substr($s,0,1,'UTF-8'),'UTF-8');}function groupIdByName(PDO $pdo,string $n):?int{$q=$pdo->prepare("SELECT id FROM `groups` WHERE name=? LIMIT 1");$q->execute([$n]);$gid=$q->fetchColumn();return $gid?(int)$gid:null;}function weekTypeFor(string $d,DateTimeZone $tz):string{[,,,$t]=computeSemesterAndWeek(new DateTime($d,$tz));return $t;}$me=tg_require_auth();$me_tg=(int)$me['tg_id'];$PRIMARY_GROUP_NAME=PRIMARY_GROUP_NAME;$SECONDARY_TG_ID=(int)SECONDARY_TG_ID;if(isset($_GET['view'])){$v=$_GET['view'];if($v==='primary')$_SESSION['view_group_id']=groupIdByName($pdo,$PRIMARY_GROUP_NAME);elseif($v==='reset')unset($_SESSION['view_group_id']);$w=isset($_GET['when'])?('?when='.urlencode($_GET['when'])):'';header('Location: greeting.php'.$w);exit;}$act_tg=$me_tg;$act_user=$me;$imp=false;if(($me['role']??'')==='admin'&&isset($_GET['tg_id'])&&ctype_digit((string)$_GET['