er,$view_sub);} $layout=$_COOKIE['tableLayout']??'small';$base=rtrim(dirname($_SERVER['SCRIPT_NAME']),'/\\');$cssS=$base.'/style.css?v='.(file_exists(__DIR__.'/style.css')?filemtime(__DIR__.'/style.css'):time());$cssB=$base.'/tableb.css?v='.(file_exists(__DIR__.'/tableb.css')?filemtime(__DIR__.'/tableb.css'):time());$cssC=$base.'/tablec.css?v='.(file_exists(__DIR__.'/tablec.css')?filemtime(__DIR__.'/tablec.css'):time());$impQ=$imp?('&tg_id='.urlencode((string)$act_tg)):'';
?><!DOCTYPE html><html lang="en" class="<?= $thCls ?>"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Greeting</title><link rel="stylesheet" href="<?= htmlspecialchars($cssS,ENT_QUOTES) ?>"><link rel="stylesheet" href="<?= htmlspecialchars($cssC,ENT_QUOTES) ?>" id="css-small" media="all"><?php if($when==='week'):?><link rel="stylesheet" href="<?= htmlspecialchars($cssB,ENT_QUOTES) ?>" id="css-big" media="<?= ($layout==='big')?'all':'not all' ?>"><?php endif;?><script src="https://telegram.org/js/telegram-web-app.js"></script><script src="script.js"></script></head><body><br><div id="theme-switch"><label class="switch"><input type="checkbox" id="theme-toggle" <?= $th==='dark'?'checked':'' ?>><span class="slider"></span></label><span id="theme-label"><?= $th==='dark'?'Dark':'Light' ?></span><?php if($when==='week'):?><label class="switch" style="margin-left:.75rem"><input type="checkbox" id="table-toggle"><span class="slider"></span></label><span id="table-label"><?= ($layout==='big')?'Big':'Compact' ?></span><?php endif;?></div><br><br><h1>Hello, <?= htmlspecialchars($act_user['name'],ENT_QUOTES) ?>!</h1><?php if(($act_user['role']??'student')!=='student'):?><p>Role:<strong><?= ucfirst(htmlspecialchars($act_user['role'])) ?></strong></p><?php endif;?><nav><a class="btn" data-when="yesterday" href="?when=yesterday<?= $impQ ?>">← Yesterday</a><a class="btn" data-when="today" href="?when=today<?= $impQ ?>">Today</a><a class="btn" data-when="tomorrow" href="?when=tomorrow<?= $impQ ?>">Tomorrow →</a><a class="btn" data-when="week" href="?when=week<?= $impQ ?>">This Week</a></nav><h2><?= htmlspecialchars($label,ENT_QUOTES) ?>’s Schedule</h2><p>This is an <span class="week-type <?= htmlspecialchars($banner,ENT_QUOTES) ?>"><?= ucfirst($banner) ?></span> week.</p><?php if($when==='week'):?><?php if(empty($grid)):?><p>No classes scheduled this week.</p><?php else:?><table class="schedule-table"><colgroup><col class="col-time"><?php for($i=0;$i<count($dayLabels);$i++):?><col class="col-day"><?php endfor;?></colgroup><thead><tr><th>Time</th><?php foreach($dayLabels as $d):?><th><?= htmlspecialchars($d,ENT_QUOTES) ?></th><?php endforeach;?></tr></thead><?php $slots=array_filter($timeSlots,function($s)use($dayLabels,$grid){foreach($dayLabels as $d)if(!empty($grid[$s][$d]))return true;return false;});?><tbody><?php foreach($slots as $s):?><tr><td rowspan="2"><?= htmlspecialchars($s,ENT_QUOTES) ?></td><?php foreach($dayLabels as $d):$c=$grid[$s][$d]??[];$full=array_filter($c,fn($x)=>$x['week_type']===null);$odd=array_filter($c,fn($x)=>$x['week_type']==='odd');$even=array_filter($c,fn($x)=>$x['week_type']==='even');?><?php if(count($full)):$x=reset($full);?><td rowspan="2" class="week-cell"><?= htmlspecialchars($x['type']??'',ENT_QUOTES) ?>.<?php $sub=$x['subject'];?><span class="subject" aria-label="<?= htmlspecialchars($sub) ?>"><span class="subject-full"><?= htmlspecialchars($sub) ?></span><abbr class="subject-short" title="<?= htmlspecialchars($sub) ?>"><?= htmlspecialchars(initials($sub)) ?></abbr></span><br><?php if(!empty($x['location'])):?><small><?= htmlspecialchars($x['location'],ENT_QUOTES) ?></small><?php endif;?></td><?php elseif(count($odd)&&count($even)):?><td class="week-cell odd"><?php foreach($odd as $x):?><?= htmlspecialchars($x['type']??'',ENT_QUOTES) ?>.<?php $s2=$x['subject'];?><span class="subject" aria-label="<?= htmlspecialchars($s2) ?>"><span class="subject-full"><?= htmlspecialchars($s2) ?></span><abbr class="subject-short" title="<?= htmlspecialchars($s2) ?>"><?= htmlspecialchars(initials($s2)) ?></abbr></span><br><?php if(!empty($x['location'])):?><small><?= htmlspecialchars($x['location'],ENT_QUOTES) ?></small><br><?php endif;?><?php endforeach;?></td><?php elseif(count($odd)):?><td class="week-cell odd"><?php foreach($odd as $x):?><?= htmlspecialchars($x['type']??'',ENT_QUOTES) ?>.<?php $s2=$x['subject'];?><span class="subject" aria-label="<?= htmlspecialchars($s2) ?>"><span class="subject-full"><?= htmlspecialchars($s2) ?></span><abbr class="subject-short" title="<?= htmlspecialchars($s2) ?>"><?= htmlspecialchars(initials($s2)) ?></abbr></span><br><?php if(!empty($x['location'])):?><small><?= htmlspecialchars($x['location'],ENT_QUOTES) ?></small><br><?php endif;?><?php endforeach;?></td><?php else:?><td>&nbsp;</td><?php endif;?><?php endforeach;?></tr><tr><?php foreach($dayLabels as $d):$c=$grid[$s][$d]??[];$full=array_filter($c,fn($x)=>$x['week_type']===null);$odd=array_filter($c,fn($x)=>$x['week_type']==='odd');$even=array_filter($c,fn($x)=>$x['week_type']==='even');?><?php if(count($full)):?><?php continue;?><?php elseif(count($odd)&&count($even)):?><td class="week-cell even"><?php foreach($even as $x):?><?= htmlspecialchars($x['type']??'',ENT_QUOTES) ?>.<?php $s2=$x['subject'];?><span class="subject" aria-label="<?= htmlspecialchars($s2) ?>"><span class="subject-full"><?= htmlspecialchars($s2) ?></span><abbr class="subject-short" title="<?= htmlspecialchars($s2) ?>"><?= htmlspecialchars(initials($s2)) ?></abbr></span><br><?php if(!empty($x['location'])):?><small><?= htmlspecialchars($x['location'],ENT_QUOTES) ?></small><br><?php endif;?><?php endforeach;?></td><?php elseif(count($even)):?><td class="week-cell even"><?php foreach($even as $x):?><?= htmlspecialchars($x['type']??'',ENT_QUOTES) ?>.<?php $s2=$x['subject'];?><span class="subject" aria-label="<?= htmlspecialchars($s2) ?>"><span class="subject-full"><?= htmlspecialchars($s2) ?></span><abbr class="subject-short" title="<?= htmlspecialchars($s2) ?>"><?= htmlspecialchars(initials($s2)) ?></abbr></span><br><?php if(!empty($x['location'])):?><small><?= htmlspecialchars($x['location'],ENT_QUOTES) ?></small><br><?php endif;?><?php endforeach;?></td><?php else:?><td>&nbsp;</td><?php endif;?><?php endforeach;?></tr><?php endforeach;?></tbody></table><?php endif;?><?php elseif(empty($schedule)):?><p>No classes scheduled <?= $when==='today'?'today':'for '.htmlspecialc