<?php if(($me['role']??'')==='admin'):?><a class="btn btn-primary" href="greeting.php?view=primary<?= '&when='.urlencode($when) ?>">Primary</a><?php if($SECONDARY_TG_ID>0):?><a class="btn btn-primary" href="greeting.php?tg_id=<?= (int)$SECONDARY_TG_ID.'&when='.urlencode($when) ?>">Secondary</a><?php endif;?><?php if(!empty($_SESSION['view_group_id'])||$imp):?><a class="btn btn-primary" href="greeting.php?view=reset<?= '&when='.urlencode($when) ?>">Reset</a><?php endif;?><?php endif;?></div><script>(function(){const cur=(new URL(location.href)).searchParams.get('when')||'today';document.querySelectorAll('nav a.btn[data-when]').forEach(a=>{if((a.getAttribute('data-when')||'today')===cur){a.addEventListener('click',e=>e.preventDefault(),{passive:false});a.setAttribute('aria-current','page');}});})();</script></body></html>
